          </label>
          <label>
            <span>地点</span>
            <input v-model="draft.location" placeholder="例如：旧教学楼二楼" />
          </label>
        </section>

        <section class="summary-card">
          <div class="card-title"><i class="fa-solid fa-align-left"></i> 剧情概览</div>
          <textarea v-model="draft.overview" placeholder="用一段话概括这一段剧情"></textarea>
        </section>

        <section class="summary-card">
          <div class="card-title">
            <span><i class="fa-solid fa-list-check"></i> 重要事件</span>
            <button class="small-button" @click="draft.events.push('')">+ 添加事件</button>
          </div>
          <div v-for="(_, index) in draft.events" :key="`event-${index}`" class="line-editor">
            <span class="index-badge">{{ index + 1 }}</span>
            <input v-model="draft.events[index]" placeholder="事件内容" />
            <button class="danger-icon" @click="draft.events.splice(index, 1)">
              <i class="fa-solid fa-trash"></i>
            </button>
          </div>
        </section>

        <section class="summary-card">
