        <button class="secondary-button" @click="$emit('copy-markdown', draft)">复制 Markdown</button>
        <button class="secondary-button" @click="$emit('generate-candidates', draft)">补世界书候选</button>
        <button class="secondary-button" @click="$emit('save', draft)">保存总结</button>
        <button class="primary-button" @click="$emit('write-worldbook', draft)">写入勾选世界书</button>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { defineComponent, h, reactive, watch } from 'vue';
import { createEmptyVisualSummary, type VisualSummary } from '../types/visual-summary';

const props = defineProps<{
  show: boolean;
  summary: VisualSummary | null;
}>();

defineEmits<{
  close: [];
  save: [summary: VisualSummary];
  'copy-json': [summary: VisualSummary];
  'copy-markdown': [summary: VisualSummary];
  'generate-candidates': [summary: VisualSummary];
  'write-worldbook': [summary: VisualSummary];
}>();

const draft = reactive<VisualSummary>({
  title: '',
  range: { start: 0, end: 0 },
  time: '',
  location: '',
  overview: '',
  events: [],
  characters: [],
  relationshipChanges: [],
  foreshadowing: [],
  todo: [],
  worldbookCandidates: [],
});

function loadSummary(summary: VisualSummary | null) {
  const empty = createEmptyVisualSummary(0, 0);
  Object.assign(draft, JSON.parse(JSON.stringify(summary || empty)));
}

watch(
  () => props.summary,
  summary => loadSummary(summary),
  { immediate: true, deep: true },
);

function addCharacter() {
  draft.characters.push({ name: '', status: '', attitude: '', memory: '' });
}

function addRelation() {
  draft.relationshipChanges.push({ from: '', to: '', change: '', reason: '' });
}

function addWorldbookCandidate() {
  draft.worldbookCandidates.push({ type: 'other', title: '', content: '', enabled: true });
}

const EditableList = defineComponent({
  props: {
    modelValue: { type: Array as () => string[], required: true },
    title: { type: String, required: true },
    placeholder: { type: String, required: true },
  },
  emits: ['update:modelValue'],
  setup(props, { emit }) {
    const update = (items: string[]) => emit('update:modelValue', items);
    return () =>
      h('div', { class: 'editable-list' }, [
        h('div', { class: 'editable-list-title' }, [
          h('span', props.title),
          h(
            'button',
            {
              class: 'small-button',
              onClick: () => update([...props.modelValue, '']),
            },
            '+ 添加',
          ),
        ]),
        ...props.modelValue.map((item, index) =>
          h('div', { class: 'line-editor' }, [
            h('input', {
              value: item,
              placeholder: props.placeholder,
              onInput: (event: Event) => {
                const next = [...props.modelValue];
                next[index] = (event.target as HTMLInputElement).value;
                update(next);
              },
            }),
            h(
              'button',
              {
                class: 'danger-icon',
                onClick: () => update(props.modelValue.filter((_, i) => i !== index)),
              },
              [h('i', { class: 'fa-solid fa-trash' })],
            ),
          ]),
        ),
      ]);
  },
});
</script>

