export const buildToolsStorageKey = (scriptId: string): string => `${scriptId}_tools_data`;

export function loadToolsDataFromStorage<T extends Record<string, any>>(scriptId: string, fallback: T): T {
  try {
    const storageKey = buildToolsStorageKey(scriptId);
    const raw = localStorage.getItem(storageKey);

    if (!raw) {
      return fallback;
    }

    const parsed = JSON.parse(raw);
    if (parsed && typeof parsed === 'object') {
      return parsed as T;
    }
  } catch (error) {
    console.error('Failed to load tools data from localStorage:', error);
  }

  return fallback;
}

export function saveToolsDataToStorage(scriptId: string, data: unknown): void {
  const storageKey = buildToolsStorageKey(scriptId);
  localStorage.setItem(storageKey, JSON.stringify(data));
}
